INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Participa ativamente do trabalho em equipe, recebe e transmite informações de forma padronizada (SBAR)Comunicação SBAR / trabalho em equipe?',1,'A comunicação SBAR é uma ferramenta padronizada de transferência de informações essencial para a segurança do paciente e para o trabalho em equipe',true,'2026-06-30 13:17:59.727302','autoavaliacao','b711af17-c67d-4373-9149-3c962539cc3d'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente Consciência situacional NTS?',1,'A manutenção da consciência situacional (Habilidade Não Técnica - HNT) evita a fixação de foco e a sobrecarga de trabalho. Monitorar paciente, equipamentos e ambiente simultaneamente, além de identificar sinais precoces de deterioração clínica e comunicar efetivamente, previne erros e é essencial para a segurança no cuidado.',true,'2026-06-30 13:21:58.727001','autoavaliacao','e0f1a7bd-a731-458f-9ecc-c9b50c12ffae'::uuid),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Manuseia corretamente: oxímetro, monitor cardíaco, respirador, glicosímetro e demais equipamentos da USB/USA Manuseio de equipamentos?',1,'O manuseio adequado foca na segurança do paciente, estabilização dos sinais vitais e transporte seguro',true,'2026-06-30 13:19:15.285353','autoavaliacao','ccc493c8-bab0-4999-b1a6-d4a421058e81'::uuid),
	 ('Técnico de Enfermagem','Metas e desenvolvimento - Transversais','Busco ativamente meu desenvolvimento profissional por meio de capacitações, leituras, treinamentos inlocco, e trocas com equipe?',1,'Essa postura de aprendizagem contínua — chamada de Lifelong Learning — é essencial para manter a empregabilidade, desenvolver novas competências e destacar-se no mercado atual',true,'2026-06-30 13:24:24.86345','autoavaliacao','26d22fb1-f3c8-42e7-a9f6-4d50efca2735'::uuid),
	 ('Técnico de Enfermagem','Metas e desenvolvimento - Transversais','Tenho clareza sobre minhas motivações profissionais que nos mantém engajado no trabalho no SAMU 192',1,'As motivações para atuar no SAMU 192 geralmente giram em torno do propósito de salvar vidas, da adrenalina e dinamismo do Atendimento Pré-Hospitalar (APH) e do compromisso em fortalecer a saúde pública',true,'2026-06-30 13:25:18.41566','autoavaliacao','2a113a5f-59c2-4595-a593-def2580d0610'::uuid),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Executa corretamente compressões torácicas, ventilação (bolsa-valva-máscara) e desfibrilação com DEA conforme protocolo RCP e DEA?',1,'O protocolo de Suporte Básico de Vida (SBV) para PCR baseia-se na sequência C-A-B-D.',true,'2026-06-30 13:18:28.638346','autoavaliacao','9c3ad4d5-f516-49df-b540-99c036b15aa0'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Toma decisões clínicas rápidas e assertivas em cenários de IAM, AVC, trauma grave, sepse e PCR Decisão clínica em urgências?',1,'Decisões rápidas e assertivas em emergências dependem do reconhecimento de síndromes tempo-dependentes.',true,'2026-06-30 13:19:52.671911','autoavaliacao',NULL),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Realiza punção venosa periférica, coleta e administra medicamentos conforme prescrição do Enfermeiro/médico Punção venosa / medicação?',1,'A punção venosa periférica e a administração de medicamentos são procedimentos regulamentados que exigem capacitação técnica e obediência estrita às prescrições do enfermeiro ou médico.',true,'2026-06-30 13:20:21.110296','autoavaliacao','4c2c829d-e1fb-4a7b-b131-1466a02ef16d'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência) Controle emocional?',1,'Manter a calma em situações de alta pressão, como PCR ou múltiplas vítimas, exige treinamento e técnicas rápidas de regulação psicofisiológica.',true,'2026-06-30 13:21:21.239054','autoavaliacao','3324e363-d79c-4a7b-80c0-566c4ba62707'::uuid),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','Reconheço e valorizo as contribuições dos meus colegas e gestores dando e recebendo feedback com abertura?',1,'Reconhecer e valorizar o trabalho é fundamental para promover a melhoria contínua e um ambiente colaborativo. Praticar o feedback exige inteligência emocional para manter uma escuta ativa, focar no desenvolvimento profissional e evitar posturas defensivas',true,'2026-06-30 13:23:27.862939','autoavaliacao','a0b47168-b65f-4dbd-8a0f-be96260bd257'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','Identifica e comunica sinais de gravidade imediata ao Enfermeiro/médico com precisão, agilidade Triagem e comunicação?',1,'Identificar e comunicar sinais de alerta com precisão e agilidade é vital na triagem. Durante o Acolhimento com Classificação de Risco',true,'2026-06-30 13:22:25.766942','autoavaliacao','4559065d-f39b-47a0-bbdf-706c716ebde7'::uuid),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','Avalia a segurança da cena antes de aproximação e comunica riscos à equipe (tráfego, violência, substâncias) Segurança da cena?',1,'A avaliação e o controle da segurança da cena são os passos mais críticos no Atendimento Pré-Hospitalar (APH) e Suporte Básico de Vida (SBV).',true,'2026-06-30 13:23:03.7284','autoavaliacao',NULL),
	 ('Médico','EIXO TÉCNICO','Conduz a PCR conforme ACLS: algoritmo, ritmo, medicação, tempo de RCP, ROSC — taxa de retorno adequada?',1,'A condução de uma Parada Cardiorrespiratória (PCR) no Suporte Avançado de Vida em Cardiologia (ACLS) baseia-se na RCP de alta qualidade',true,'2026-07-03 15:25:26.733','autoavaliacao','6f2d51f9-b655-4b46-9a41-c4054fc1d9c1'::uuid),
	 ('Médico','EIXO TÉCNICO','Realiza avaliação clínica completa e rápida, formulando diagnóstico sindromático correto no pré-hospitalar?',1,'No atendimento pré-hospitalar (APH), a avaliação clínica baseia-se em protocolos padronizados de resposta rápida.',true,'2026-07-03 15:25:26.733','autoavaliacao','b9a28f1f-9de0-4ba1-b46c-6a86010c75be'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Aborda paciente e família com empatia, respeito, escuta ativa e informação adequada mesmo em cenários críticos?',1,'Abordar pacientes e famílias em cenários críticos exige humanização e técnica.',true,'2026-07-03 15:25:26.733','autoavaliacao','dd7061b1-e2fc-4aca-9ae9-81697b494398'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Comunica decisões de forma clara, utiliza comunicação em loop com a equipe e mantém registro verbal de ordens?',1,'Essas características descrevem um líder altamente organizado e focado em alta confiabilidade, prevenindo falhas de execução através de três pilares de excelência',true,'2026-07-03 15:25:26.733','autoavaliacao','d6f4087c-859d-447a-a8dc-35fac7ac91ca'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Mantenho a calma e o tom de voz firme para estabilizar a equipe, o paciente e os familiares em momentos de desespero ou conflito?',1,'Demostrar habilidade essencial de liderança em ambientes de alta pressão, conhecida como comunicação de crise e gestão de agitação.',true,'2026-07-03 15:25:26.733','autoavaliacao','20b9a899-6c07-4122-9f11-0b3a7e975c31'::uuid),
	 ('Médico','EIXO SOFT SKILLS','Lidera a equipe USA com autoridade, clareza e empatia: define papéis, distribui tarefas, mantém hierarquia e segurança?',1,'Liderar a equipe USA exige alinhar objetivos estratégicos com o desenvolvimento humano. Com autoridade para guiar, clareza na comunicação e empatia para apoiar, a gestão baseia-se em delegar responsabilidades, manter uma hierarquia de respeito mútuo e garantir um ambiente de trabalho seguro e focado em resultados',true,'2026-07-03 15:25:26.733','autoavaliacao','72717930-6c10-44b7-b799-f58e213b2048'::uuid),
	 ('Médico','EIXO PEOPLE SKILLS','Mantém consciência situacional ampla (cena, paciente, equipe, recursos, tempo) e adapta o plano de cuidado?',1,'A consciência situacional é a capacidade dinâmica de observar, compreender e antecipar eventos',true,'2026-07-03 15:25:26.733','autoavaliacao','ef2e206a-abdd-4407-ab23-267ffdf53344'::uuid),
	 ('Médico','EIXO PEOPLE SKILLS','Toma decisões rápidas e assertivas sob pressão extrema, com base em evidências e priorização correta?',1,'Tomar decisões rápidas e assertivas sob pressão exige um método estruturado para evitar a paralisia ou o pânico. O segredo é agir com base em dados concretos, filtrando o ruído e focando no que realmente importa para a resolução do problema.',true,'2026-07-03 15:25:26.733','autoavaliacao','4e8fe99d-8c6c-4a44-90f7-914324f63bca'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Médico','Metas e desenvolvimento - Transversais','Sou receptivo(a) a feedbacks construtivos da equipe após uma ocorrência.? É excelente ter essa abertura?',1,'Profissionais que acolhem feedbacks construtivos após incidentes transformam falhas em oportunidades de aprendizado e fortalecem a confiança e colaboração em toda a equipe.',true,'2026-07-03 15:25:26.733','autoavaliacao','eb003a38-0576-4513-941f-0e96c10120c9'::uuid),
	 ('Médico','Metas e desenvolvimento - Transversais','Utilizo comunicação em loop fechado (call-out e check-back) de forma consistente nos atendimentos.?',1,'A comunicação em loop fechado (alça fechada) é um dos pilares da Comunicação Efetiva, essencial para cumprir as metas internacionais de segurança do paciente, prevenir falhas e garantir que condutas críticas sejam executadas',true,'2026-07-03 15:25:26.733','autoavaliacao','1896b652-49b2-4ff6-872a-7cd51c1d3372'::uuid),
	 ('Médico','EIXO TÉCNICO','Comunica-se eficientemente com o médico regulador da CRUR-BF: informações precisas, decisão conjunta, tempo de regulação?',1,'A comunicação eficiente com o médico regulador da CRUR-BF (Central de Regulação de Urgências da Baixada Fluminense) baseia-se em três pilares: clareza e precisão dos dados clínicos, definição conjunta da conduta (acordo mútuo) e agilidade no tempo-resposta',true,'2026-07-03 15:25:26.733','autoavaliacao','3073a67a-c483-4281-811f-be56744cda1e'::uuid),
	 ('Médico','EIXO TÉCNICO','Executa procedimentos de SAV com excelência: IOT difícil, acesso intraósseo, drenagem, cardioversão?',1,'A execução de excelência nos procedimentos de Suporte Avançado de Vida (SAV) exige domínio técnico, raciocínio rápido e seguimento estrito dos algoritmos.',true,'2026-07-03 15:25:26.733','autoavaliacao','9ca9c91f-31a4-45b8-9047-b912ca303d75'::uuid),
	 ('Enfermeiro','Metas e desenvolvimento - Transversais','Usa comunicação em loop fechado (call-out, check-back) para garantir compreensão das ordens na cena?',1,'Essa é a base da comunicação em circuito fechado (closed-loop communication), protocolo padrão-ouro de segurança.',true,'2026-07-03 15:14:49.988354','autoavaliacao','22b4d3f8-c2a6-49b1-a436-dab096365ca2'::uuid),
	 ('Enfermeiro','EIXO PEOPLE SKILLS','Contribui para metas operacionais: tempo-resposta ≤15min, tempo de cena ≤20min, ROSC em PCR?',1,'Essas são metas operacionais críticas no Atendimento Pré-Hospitalar (APH).',true,'2026-07-03 15:14:49.988354','autoavaliacao','f095b371-16fb-4a57-bc3c-1e26d1ca3631'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Executa corretamente compressões torácicas, ventilação (bolsa-valva-máscara) e desfibrilação com DEA conforme protocolo RCP e DEA?',1,'A Reanimação Cardiopulmonar (RCP) com uso de DEA e bolsa-valva-máscara (BVM) segue o protocolo de Suporte Básico de Vida (SBV). O objetivo é garantir a oxigenação cerebral e manter o fluxo sanguíneo.',true,'2026-07-03 15:14:49.988354','autoavaliacao','02996b6e-f228-4e51-a266-b72b9d81b9a0'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Mantém foco e equilíbrio emocional em situações de alta pressão (PCR, múltiplas vítimas, violência?)',1,'Em situações de alta pressão, manter a calma é vital. A regra de ouro é focar no próximo passo lógico—como checar vias aéreas na PCR ou triagem no trauma—e dominar respostas fisiológicas através do treinamento',true,'2026-07-03 15:14:49.988354','autoavaliacao','5ede0553-6a07-448c-b994-ae2022b00b17'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Participa ativamente do trabalho em equipe, recebe e transmite informações de forma padronizada (SBAR)?',1,'A comunicação SBAR é um método padronizado de transmissão de informações na área da saúde.',true,'2026-07-03 15:14:49.988354','autoavaliacao','cd5090a4-ffd6-4285-bb9b-02f7dff0cb1c'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Mantém consciência situacional: monitora o estado do paciente, equipamentos e ambiente simultaneamente?',1,'A consciência situacional na assistência ao paciente é a base da segurança e da eficácia clínica.',true,'2026-07-03 15:14:49.988354','autoavaliacao','a7804c47-2332-43f9-aeb7-d340ece689d8'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Enfermeiro','EIXO TÉCNICO','Administra medicamentos de urgência com segurança, verificando via, dose, concentração e registro?',1,'administração segura de medicamentos de urgência exige a checagem rigorosa dos "13 Certos", focando especialmente na via (ex: EV, IM), dose, concentração (para evitar erros de diluição) e registro (que deve ser imediato)',true,'2026-07-03 15:14:49.988354','autoavaliacao','459c399f-45dd-45e9-a784-92c2c4467ed9'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Executa técnica correta de movimentação e transporte de pacientes críticos sem agravar lesões?',1,'A movimentação e o transporte seguros de pacientes críticos exigem planejamento sistematizado para evitar quedas, extubações acidentais, desconexão de drogas vasoativas e agravamento de lesões.',true,'2026-07-03 15:14:49.988354','autoavaliacao','4a820846-bb4d-41c2-8ff0-8ad6e1fdb5d7'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Realiza avaliação primária (ABCDE) de forma rápida, sistemática e correta após chegada na cena?',1,'A avaliação primária é um método sistemático e rápido de triagem para identificar e tratar ameaças imediatas à vida.',true,'2026-07-03 15:14:49.988354','autoavaliacao','ced22b4d-243d-4730-981e-42ec2899fce1'::uuid),
	 ('Enfermeiro','EIXO PEOPLE SKILLS','Registra o Processo de Enfermagem no SAMU de forma completa, legível e juridicamente válida?',1,'O registro do Processo de Enfermagem (PE) no SAMU deve ser completo, legível e juridicamente válido.',true,'2026-07-03 15:14:49.988354','autoavaliacao','3b719682-f25d-484c-ad7d-8e03ccec9487'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','Usa corretamente todos os EPIs e adota medidas de segurança para si, paciente e equipe em toda cena?',1,'O uso correto dos Equipamentos de Proteção Individual (EPIs) e a segurança da cena são os pilares do Atendimento Pré-Hospitalar (APH) e de emergências.',true,'2026-07-03 15:14:49.988354','autoavaliacao','ec03cbf4-ab92-4220-8266-4b69b5f66d3c'::uuid),
	 ('Enfermeiro','Metas e desenvolvimento - Transversais','Exerce liderança na USB/USA: dirige a equipe com clareza, distribui tarefas e coordena o atendimento?',1,'A comunicação em circuito fechado (closed-loop communication) é uma técnica estruturada baseada em feedback. Ela evita ambiguidades e falhas humanas, sendo vital para ambientes de alta pressão',true,'2026-07-03 15:14:49.988354','autoavaliacao','d3bd49bb-47c4-413d-8965-8e3a99ed9336'::uuid),
	 ('Condutor','Metas e desenvolvimento - Transversais','Tenho clareza sobre minhas motivações profissionais que nos mantém engajado no trabalho no SAMU 192',1,'Compreender as próprias motivações no SAMU 192 é o que fortalece a resiliência diária e o vínculo com a missão de salvar vidas.',true,'2026-06-30 11:20:41.748116','autoavaliacao','bbefebdb-2f27-4bff-8760-76c1f3fa47ba'::uuid),
	 ('Condutor','EIXO PEOPLE SKILLS','Avalia a segurança da cena antes de aproximação e comunica riscos à equipe (tráfego, violência, substâncias)',1,'A segurança da cena é a prioridade máxima no Atendimento Pré-Hospitalar (APH)',true,'2026-06-30 11:13:01.386777','autoavaliacao','5f4dd6bc-1414-4c93-b3a1-7ac628e993c0'::uuid),
	 ('Condutor','EIXO PEOPLE SKILLS','Reconheço e valorizo as contribuições dos meus colegas e gestores dando e recebendo feedback com abertura?',1,'Reconhecer e valorizar a equipe através do feedback é fundamental para um ambiente de trabalho saudável e de alto desempenho!',true,'2026-06-30 11:13:33.096019','autoavaliacao','574c0d3c-65cb-497e-8224-caba22467e46'::uuid),
	 ('Condutor','EIXO SOFT SKILLS','Trata pacientes, familiares e equipe com respeito, sigilo e ética, respeitando a dignidade humana Ética e humanização.',1,'Esse é um pilar fundamental para qualquer profissional da área da saúde ou do cuidado humano. A prática baseada no respeito, sigilo, ética e dignidade garante um ambiente seguro e acolhedor para todos os envolvidos',true,'2026-06-30 11:02:57.776166','autoavaliacao','3323ee62-b181-4fa7-96bf-e2c732b3af8f'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','EIXO TÉCNICO','Manuseia corretamente a maca, cadeira de rodas, prancha longa e colar cervical (Manuseio de equipamentos)',1,'Manuseio correto de equipamentos de imobilização e transporte exige treinamento, comunicação constante e movimentação em bloco.',true,'2026-06-30 11:16:11.659225','autoavaliacao','891047b8-1247-42a5-9749-802f3f3ea185'::uuid),
	 ('Condutor','EIXO SOFT SKILLS','Mantém controle emocional em cenários de alta tensão, múltiplas vítimas, violência ou óbito Controle emocional.',1,'Manter o controle emocional é vital para a segurança e a eficácia da equipe. Gerencie o estresse focando no momento presente, adotando técnicas de respiração e separando a empatia do sofrimento.',true,'2026-06-30 11:03:42.352605','autoavaliacao','0acb3080-5013-452c-a9e2-ba702417de1a'::uuid),
	 ('Condutor','EIXO TÉCNICO','Realiza checklist completo da viatura no início do plantão (combustível, pneus, equipamentos, kit de emergência) ',1,'Checklist preenchido? Rotinas e normas operacionais',true,'2026-06-30 11:17:01.050808','autoavaliacao','9d3e1a85-92c2-4468-998b-79d903745d69'::uuid),
	 ('Condutor','EIXO SOFT SKILLS','Contribuo ativamente para o trabalho em equipe multiprofissional durante as ocorrências e na base.',1,'Comunicação assertiva e respeito aos saberes de cada área.',true,'2026-06-30 11:04:17.447805','autoavaliacao','c0a23f7a-d70d-4ad5-9a77-91ee85142437'::uuid),
	 ('Condutor','EIXO TÉCNICO','Considero que meu domínio dos protocolos assistências e diretrizes do SAMU está atualizado (EX. Suporte Básico de Vida (SBV): RCP, imobilização, oxigenoterapia) e compatível com minha função (ex. Pratica direção defensiva com habilidade, respeitando sinalização e segurança da equipe e paciente no deslocamento de emergência)',1,'',true,'2026-06-30 11:18:14.345898','autoavaliacao','35404463-3b29-42d6-a8bc-3850c52ff644'::uuid),
	 ('Condutor','Metas e desenvolvimento - Transversais','Busco ativamente meu desenvolvimento profissional por meio de capacitações, leituras, treinamentos inlocco, e trocas com equipe.',1,'Essa é uma excelente estratégia de carreira. Combinar capacitações, leituras e trocas com a equipe garante um desenvolvimento contínuo.',true,'2026-06-30 11:19:49.690665','autoavaliacao','8aac5dcf-82b7-4d0f-bbd0-0f1567eb748c'::uuid),
	 ('Condutor','EIXO SOFT SKILLS','Contribui para o cumprimento do tempo-resposta ≤15 minutos da central ao local (Portaria MS 2.048/2002)',1,'O cumprimento do tempo-resposta de ≤ 15 minutos da Central ao local exige a descentralização das bases do SAMU, dimensionamento correto da frota, otimização das rotas de tráfego e equipes capacitadas sob rigorosa regulação médica. Em locais distantes onde o tempo terrestre supere essa marca, recomenda-se o acionamento de resgate aeromédico',true,'2026-06-30 11:11:21.321903','autoavaliacao','40ca12fd-81be-4272-8c2d-d17922d1e740'::uuid),
	 ('Condutor','EIXO TÉCNICO','Realizo autoavaliação crítica da minha prática assistências, identificando lacunas e buscando corrigi-las.',1,'Essa é uma prática fundamental e altamente recomendada na área da saúde. Realizar a autoavaliação crítica da própria prática assistencial, identificar lacunas e buscar o aprimoramento contínuo garante a segurança do paciente e a excelência no cuidado.',true,'2026-06-30 11:19:18.872887','autoavaliacao','80aaba6a-988e-4937-80a4-44d6e78ae517'::uuid),
	 ('Avaliação Par','EIXO SOFT SKILLS','Essa pessoa é alguém em quem você confia para trabalhar em uma ocorrência crítica?',1,'',true,'2026-06-16 19:12:56.829486','Par','f243b4b3-2781-44e5-9454-a879cf2ef91a'::uuid),
	 ('Avaliação Par','Desenvolvimento da Equipe','Essa pessoa contribui para um ambiente de equipe saudável ou gera desgaste desnecessário?',1,'',false,'2026-06-16 19:12:56.829486','Par','05d7ff90-43ac-4bde-9a88-336fc0090793'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Avaliação Par','EIXO PEOPLE SKILLS','Essa pessoa contribui para um ambiente de equipe saudável ou gera desgaste desnecessário?',1,'',true,'2026-06-16 19:12:56.829486','Par','05d7ff90-43ac-4bde-9a88-336fc0090793'::uuid),
	 ('Avaliação Par','Desenvolvimento da Equipe','Essa pessoa age com humildade profissional — pede ajuda quando precisa e oferece ajuda quando vê necessidade?',1,'',false,'2026-06-16 19:12:56.829486','Par','ca4d4a1c-1a68-40e4-aa7c-543bd7422738'::uuid),
	 ('Avaliação Par','Desenvolvimento da Equipe','Essa pessoa é alguém em quem você confia para trabalhar em uma ocorrência crítica?',1,'',false,'2026-06-16 19:12:56.829486','Par','f243b4b3-2781-44e5-9454-a879cf2ef91a'::uuid),
	 ('Avaliação Par','EIXO TÉCNICO','Essa pessoa age com humildade profissional — pede ajuda quando precisa e oferece ajuda quando vê necessidade?',1,'',true,'2026-06-16 19:12:56.829486','Par','ca4d4a1c-1a68-40e4-aa7c-543bd7422738'::uuid),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',true,'2026-06-30 13:32:04.689644','Liderado > Lider','579bd70c-92d5-4c0b-818d-fb446582ddcd'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider','6f457565-3aa8-4864-affb-ec4588a1392d'::uuid),
	 ('Técnico de Enfermagem','Comunicação e disponibilidade','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',false,'2026-06-30 13:34:48.761055','Liderado > Lider','2bc6babc-960b-40fe-a6d5-4b831152db1e'::uuid),
	 ('Técnico de Enfermagem','Liderança gestão','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',false,'2026-06-30 13:32:04.689644','Liderado > Lider','579bd70c-92d5-4c0b-818d-fb446582ddcd'::uuid),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',false,'2026-06-30 16:29:11.896276','Liderado > Lider','de7dd6ca-9bb5-49c3-a430-efbd288698ab'::uuid),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',true,'2026-06-30 16:28:45.057381','Liderado > Lider','78940c86-68e2-4f51-bf75-c00e9ded129b'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',true,'2026-06-30 16:27:54.328435','Liderado > Lider','97fee518-3979-4806-80e1-7ea0cdba9a6a'::uuid),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider','2bc6babc-960b-40fe-a6d5-4b831152db1e'::uuid),
	 ('Técnico de Enfermagem','EIXO SOFT SKILLS','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider','faa38a55-bf95-40aa-88e9-293e0d6a7cae'::uuid),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','As decisões do líder são tomadas com transparência critérios técnicos e considerando o impacto na equipe?',2,'No contexto do SAMU, tomar decisões técnicas (como seguir à risca os protocolos de triagem ou priorização de viaturas) e explicar os motivos de forma transparente para a equipe evita boatos na base e fortalece a confiança no comando.',true,'2026-06-30 13:32:48.121518','Liderado > Lider','c330d26c-8dcd-4311-ba2a-b3d1fa34c2eb'::uuid),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',false,'2026-06-30 16:29:41.288345','Liderado > Lider','10d3ebf1-c609-481f-81d6-de7688f4951f'::uuid),
	 ('Técnico de Enfermagem','Suporte e desenvolvimento','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',false,'2026-06-30 16:30:14.65642','Liderado > Lider','faa38a55-bf95-40aa-88e9-293e0d6a7cae'::uuid),
