	 ('Enfermeiro','EIXO TÉCNICO','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',true,'2026-06-30 16:29:41.288345','Liderado > Lider','c6e24b4e-6736-45fa-a713-4c3e56e83947'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Oferece feedback individual, construtivo e com frequência adequada (mínimo mensal), orientando o Plano de Desenvolvimento Individual (PDI)?',2,'Garantir feedback mensal para 100% da equipe operacional. Identificar lacunas de competência no atendimento de urgência. ',true,'2026-06-30 16:29:11.896276','Liderado > Lider','8dd49477-8e7e-4718-bf30-cb88fcb53dad'::uuid),
	 ('Enfermeiro','EIXO TÉCNICO','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',true,'2026-06-30 16:28:45.057381','Liderado > Lider','4ca7918c-3881-477b-8873-e15c695dd622'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Enfermeiro','EIXO SOFT SKILLS','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',true,'2026-06-30 13:36:05.370723','Liderado > Lider','a99acf21-25c3-4085-b97b-b6cdfd66ae24'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider','ce58ac27-8629-4419-98b1-375c54b54881'::uuid),
	 ('Enfermeiro','Liderança gestão','O líder demonstra domínio técnico e conhecimento das rotinas suficientes para orientar a equipe com segurança?',2,'o líder precisa dominar as rotinas operacionais (fluxos de regulação, protocolos contratuais) e os protocolos assistenciais de ponta (como o PHTLS, ACLS e diretrizes de trauma/cardio) para que a equipe sinta total segurança ao seguir suas ordens em situações críticas.',false,'2026-06-30 13:33:32.9942','Liderado > Lider','2d075c7a-3857-46ae-a5b3-e897993981bf'::uuid),
	 ('Enfermeiro','Suporte e desenvolvimento','O líder incentiva a desenvolvimento profissional da equipe, apoiando capacitações e o crescimento na carreira?',2,'Incentiva a equipe a fazer cursos de especialização (como suporte avançado de vida) e progredir na carreira de urgência e emergência.',false,'2026-06-30 16:29:41.288345','Liderado > Lider','c6e24b4e-6736-45fa-a713-4c3e56e83947'::uuid),
	 ('Enfermeiro','Comunicação e disponibilidade','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',false,'2026-06-30 16:27:54.328435','Liderado > Lider','9e2f3240-e7f2-4eb1-bea2-9f588882b489'::uuid),
	 ('Enfermeiro','EIXO SOFT SKILLS','O líder está disponível e acessível quando a equipe precisa de suporte, orientação ou decisão rápida?',2,'onde os segundos salvam vidas e as crises operacionais acontecem a qualquer hora do dia ou da noite, ter um líder acessível para resolver impasses de frota, problemas na regulação ou conflitos na base é fundamental.',true,'2026-06-30 16:27:54.328435','Liderado > Lider','9e2f3240-e7f2-4eb1-bea2-9f588882b489'::uuid),
	 ('Enfermeiro','Liderança gestão','O(s) líder coordena a equipe de forma organizada, distribuindo tarefas com clarezas e justiça?',2,'isso é fundamental para garantir que as escalas de plantão, a divisão de responsabilidades pela checagem das viaturas (insumos/medicamentos) e a limpeza da base sejam feitas de forma equilibrada, sem sobrecarregar nenhum profissional.',false,'2026-06-30 13:32:04.689644','Liderado > Lider','c34d6666-76b7-4677-9c06-ab9c6d9b0910'::uuid),
	 ('Enfermeiro','EIXO PEOPLE SKILLS','Acompanha a prática assistencial diária da equipe e o planejamento de tripulação, orientando os membros em seus primeiros passos?',2,'A líder monitora ativamente os atendimentos diários para garantir a qualidade assistencial. Realiza o planejamento e ajuste da tripulação (escala) de forma justa e eficiente. Executa o processo de acolhimento e treinamento prático de novos colaboradores (onboarding).',true,'2026-06-30 13:34:48.761055','Liderado > Lider','a6440926-645e-4a57-bcfc-b9927c205ba0'::uuid),
	 ('Enfermeiro','Suporte e desenvolvimento','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',false,'2026-06-30 16:28:45.057381','Liderado > Lider','4ca7918c-3881-477b-8873-e15c695dd622'::uuid),
	 ('Enfermeiro','Comunicação e disponibilidade','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',false,'2026-06-30 13:36:05.370723','Liderado > Lider','a99acf21-25c3-4085-b97b-b6cdfd66ae24'::uuid);
