INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Condutor','EIXO TÉCNICO','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',true,'2026-06-30 16:30:14.65642','Liderado > Lider','4cf50e89-8d1d-43e0-a112-925f4e6b8901'::uuid),
	 ('Condutor','Suporte e desenvolvimento','Promove e facilita atividades de educação permanente, simulações e capacitações na base do SAMU?',2,'Atuar na área de educação em urgências do SAMU, promover e facilitar atividades de educação permanente, desenvolver simulações realísticas e capacitações para a base.',false,'2026-06-30 16:28:45.057381','Liderado > Lider','7be335a7-c277-44ad-b553-f07955fcd822'::uuid),
	 ('Condutor','Comunicação e disponibilidade','O líder escuta ativamente as demandas, sugestões e preocupações da equipe antes de tomar decisões?',2,'No ambiente dinâmico do SAMU, ouvir a ponta antes de mudar um fluxo de atendimento ou alterar uma rotina de base evita conflitos e melhora a adesão da equipe às novas regras.',false,'2026-06-30 13:36:05.370723','Liderado > Lider','28618483-f0d5-4b13-bc26-63afecc95b86'::uuid),
	 ('Condutor','Suporte e desenvolvimento','O líder oferece suporte emocional a equipe em situações de desgaste ou eventos críticos? esse suporte é vital após eventos de alto estresse, como óbitos pediátricos, acidentes graves com múltiplas vítimas ou agressões físicas em campo.',2,'O líder atua como a primeira linha de suporte, identificando sinais de esgotamento e acionando o acolhimento psicológico institucional.',false,'2026-06-30 16:30:14.65642','Liderado > Lider','4cf50e89-8d1d-43e0-a112-925f4e6b8901'::uuid),
	 ('Técnico de Enfermagem','Entrega e Responsabilidade','Cumpre as normas de segurança, biossegurança e gestão de risco de forma consistente?',2,'',false,'2026-07-03 11:19:40.372112','Lider > Liderado','07433f2d-62a8-4763-897a-07158cf22b9e'::uuid),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Demonstra domínio atualizado dos protocolos assistenciais e diretrizes do serviço?',2,'domínio atualizado sobre os protocolos assistenciais e diretrizes terapêuticas, incluindo as atualizações correntes estabelecidas pelo Ministério da Saúde e por sociedades de especialidade Diretrizes Públicas - SBOC.',false,'2026-07-03 11:19:40.372112','Lider > Liderado',NULL),
	 ('Técnico de Enfermagem','Metas e desenvolvimento - Transversais','Qual o potencial de liderança demonstrado pelo colaborador para assumir maiores responsabilidades?',2,'',true,'2026-07-03 11:19:40.372112','Lider > Liderado',NULL),
	 ('Técnico de Enfermagem','Liderança','O colaborador entrega suas tarefas dentro do prazo estabelecido e com a qualidade técnica esperada para sua função',2,'Para enriquecer uma avaliação de desempenho ou um plano de desenvolvimento, é ideal adicionar exemplos práticos ou sugerir formas de elevar o nível atual de "esperado" para "excepcional',true,'2026-07-03 11:19:40.372112','Lider > Liderado',NULL),
	 ('Técnico de Enfermagem','EIXO TÉCNICO','Comunica-se de forma clara, objetiva e empática com colegas de equipe e gestores, inclusive em situações de alta pressão?',2,'A comunicação clara, objetiva e empática é essencial para alinhar expectativas, resolver conflitos e manter um ambiente de trabalho colaborativo e saudável, inclusive sob alta pressão.',true,'2026-07-03 11:19:40.372112','Lider > Liderado','e7cf2ca1-3895-4c58-9ebb-a6efcd7f2120'::uuid),
	 ('Técnico de Enfermagem','Comunicação e Disponibilidade','Comunica-se de forma clara, objetiva e empática com colegas de equipe e gestores, inclusive em situações de alta pressão?',2,'A comunicação clara, objetiva e empática é essencial para alinhar expectativas, resolver conflitos e manter um ambiente de trabalho colaborativo e saudável, inclusive sob alta pressão.',false,'2026-07-03 11:19:40.372112','Lider > Liderado','e7cf2ca1-3895-4c58-9ebb-a6efcd7f2120'::uuid);
INSERT INTO public.criterios_avaliacao (tipo,categoria,criterio,peso,indicador,ativo,created_at,avaliacao,codigo) VALUES
	 ('Técnico de Enfermagem','Liderança','Qual o potencial de liderança demonstrado pelo colaborador para assumir maiores responsabilidades?',2,'',false,'2026-07-03 11:19:40.372112','Lider > Liderado',NULL),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','Demonstra empatia, respeito e humanização no atendimento a pacientes, familiares e no trato com a equipe?',2,'A humanização, o respeito e a empatia são pilares essenciais no cuidado em saúde. Esse conjunto de habilidades melhora a adesão aos tratamentos, a segurança e a recuperação do paciente, além de criar um ambiente colaborativo e saudável para toda a equipe multidisciplinar.',false,'2026-07-03 11:19:40.372112','Lider > Liderado','43997435-4f27-4899-b712-305e53919baa'::uuid),
	 ('Técnico de Enfermagem','EIXO PEOPLE SKILLS','Recebe feedback e orientações com abertura, demonstrando disposição para ajustar condutas e melhorar continuamente?',2,'abertura para receber feedback e orientações. Como modelo de inteligência artificial, estou em constante processo de aperfeiçoamento para melhor atender às suas necessidades.',false,'2026-07-03 11:19:40.372112','Lider > Liderado','b7c4c3d6-b67f-405b-8bff-3da002bb46b3'::uuid),
